(1, '안녕하세요.', 'hello. (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(2, '안녕히 가세요.', 'bye. (go in peace) (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(3, '안녕히 계세요.', 'bye. (stay in peace) (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(4, '만나서 반가워요.', 'Nice to meet you. (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(5, '만나서 반갑습니다.', 'Nice to meet/see you. (formal polite)', 'phrase', '1A', 'Korean_formal_polite Korean_pattern_practice SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(6, '저는 켈리예요.', 'I am Kelly. (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(7, '저는 스티븐이에요.', 'I''m Steven. (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(8, '카말은 요리사예요.', 'Kamal is a cook. (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
(9, '줄리앙은 프랑스 사람이에요.', 'Julian is french. (polite)', 'phrase', '1A', 'Korean_pattern_practice Korean_plain_polite SNU.lvl.1 SNU.lvl.1A SNU.lvl.1A.ch1'),
